'use client';

import { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import dynamic from 'next/dynamic';
import { MovebankStudy, AnimalTrack } from '../types/movebank';
import { movebankService } from '../services/movebank';
import StudySelector from '../components/ui/StudySelector';
import AnimalPanel from '../components/ui/AnimalPanel';
import PlaybackControls from '../components/ui/PlaybackControls';

const Globe = dynamic(() => import('../components/globe/Globe'), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center text-white">
      <motion.div
        animate={{ rotate: 360 }}
        transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
        className="text-4xl"
      >
        🌍
      </motion.div>
    </div>
  ),
});

const DEFAULT_STUDY_ID = 2911040;

export default function Home() {
  const [studies, setStudies] = useState<MovebankStudy[]>([]);
  const [selectedStudyIds, setSelectedStudyIds] = useState<number[]>([]);
  const [animalTracks, setAnimalTracks] = useState<AnimalTrack[]>([]);
  const [selectedAnimal, setSelectedAnimal] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [playbackProgress, setPlaybackProgress] = useState(1);
  const [isPlaying, setIsPlaying] = useState(false);

  useEffect(() => {
    loadStudies();
    setSelectedStudyIds([DEFAULT_STUDY_ID]);
    loadStudyData([DEFAULT_STUDY_ID]);
  }, []);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isPlaying && playbackProgress < 1) {
      interval = setInterval(() => {
        setPlaybackProgress(prev => Math.min(prev + 0.005, 1));
      }, 50);
    } else if (playbackProgress >= 1) {
      setIsPlaying(false);
    }
    return () => clearInterval(interval);
  }, [isPlaying, playbackProgress]);

  async function loadStudies() {
    try {
      const res = await fetch('/api/movebank/studies?limit=50');
      const publicStudies = await res.json();
      setStudies(publicStudies);
    } catch (error) {
      console.error('Failed to load studies:', error);
    }
  }

  async function loadStudyData(studyIds: number[]) {
    setLoading(true);
    try {
      const allTracks: AnimalTrack[] = [];
      for (const studyId of studyIds) {
        const res = await fetch(`/api/movebank/study-events?studyId=${studyId}&limit=2000`);
        if (!res.ok) {
          console.error(`API error for study ${studyId}: ${res.status}`);
          continue;
        }
        const events = await res.json();
        if (!Array.isArray(events)) {
          console.error(`Expected array for study ${studyId}, got:`, events);
          continue;
        }
        const tracks = movebankService.transformToAnimalTracks(events);
        const tracksWithStudy = tracks.map(track => ({
          ...track,
          animalId: `${studyId}-${track.animalId}`,
          animalName: `${track.animalName} (Study: ${studies.find(s => s.id === studyId)?.name || studyId})`
        }));
        allTracks.push(...tracksWithStudy);
      }
      setAnimalTracks(allTracks);
      setSelectedAnimal(null);
      setPlaybackProgress(1);
      setIsPlaying(false);
    } catch (error) {
      console.error('Failed to load study data:', error);
    } finally {
      setLoading(false);
    }
  }

  const handleStudySelect = useCallback((studyId: number) => {
    setSelectedStudyIds(prev => {
      const newIds = prev.includes(studyId) 
        ? prev.filter(id => id !== studyId) 
        : [...prev, studyId];
      loadStudyData(newIds);
      return newIds;
    });
  }, []);

  const handlePlayPause = useCallback(() => {
    if (playbackProgress >= 1) {
      setPlaybackProgress(0);
    }
    setIsPlaying(prev => !prev);
  }, [playbackProgress]);

  const handleProgressChange = useCallback((value: number) => {
    setPlaybackProgress(value);
    setIsPlaying(false);
  }, []);

  const selectedTrack = animalTracks.find(t => t.animalId === selectedAnimal) || null;

  const currentTime = selectedTrack?.points[Math.floor(selectedTrack.points.length * playbackProgress)]?.timestamp || '';
  const totalTime = selectedTrack?.points[selectedTrack.points.length - 1]?.timestamp || '';

  return (
    <main className="w-full h-screen bg-[#0a0a1a] relative overflow-hidden">
      <div className="absolute inset-0 z-0">
        {loading ? (
          <div className="w-full h-full flex items-center justify-center text-white">
            <motion.div
              animate={{ opacity: [0.5, 1, 0.5] }}
              transition={{ duration: 1.5, repeat: Infinity }}
              className="text-xl"
            >
              Loading wildlife tracking data...
            </motion.div>
          </div>
        ) : (
          <Globe
            animalTracks={animalTracks}
            selectedAnimal={selectedAnimal}
            onAnimalSelect={setSelectedAnimal}
            playbackProgress={playbackProgress}
          />
        )}
      </div>

      <div className="absolute top-6 left-6 z-10">
        <StudySelector
          studies={studies}
          selectedStudyIds={selectedStudyIds}
          onStudySelect={handleStudySelect}
          loading={loading}
        />
      </div>

      <div className="absolute top-6 right-6 z-10">
        <AnimalPanel
          track={selectedTrack}
          onClose={() => setSelectedAnimal(null)}
        />
      </div>

      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10">
        <PlaybackControls
          isPlaying={isPlaying}
          progress={playbackProgress}
          onPlayPause={handlePlayPause}
          onProgressChange={handleProgressChange}
          currentTime={currentTime ? new Date(currentTime).toLocaleTimeString() : '--:--:--'}
          totalTime={totalTime ? new Date(totalTime).toLocaleTimeString() : '--:--:--'}
        />
      </div>

      <div className="absolute bottom-6 right-6 z-10">
        <motion.div
          initial={{ opacity: 0, x: 50 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.3 }}
          className="glass-panel p-3 rounded-xl text-white text-xs"
        >
          <div className="font-bold mb-1 text-blue-400">Animal Tracks</div>
          {animalTracks.slice(0, 6).map(track => (
            <motion.div
              key={track.animalId}
              whileHover={{ scale: 1.05 }}
              className="flex items-center gap-2 py-1 cursor-pointer"
              onClick={() => setSelectedAnimal(track.animalId)}
            >
              <div
                className="w-3 h-3 rounded-full"
                style={{ backgroundColor: track.color, boxShadow: `0 0 8px ${track.color}` }}
              />
              <span className="text-gray-300 text-xs">{track.animalName}</span>
            </motion.div>
          ))}
          {animalTracks.length > 6 && (
            <div className="text-gray-500 text-xs mt-1">+{animalTracks.length - 6} more</div>
          )}
        </motion.div>
      </div>

      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7 }}
        className="absolute top-6 left-1/2 -translate-x-1/2 z-10"
      >
        <h1 className="text-2xl font-bold text-white tracking-wide" style={{ textShadow: '0 0 20px rgba(0,136,255,0.8), 0 0 40px rgba(0,136,255,0.4)' }}>
          Wildlife Tracking Dashboard
        </h1>
      </motion.div>
    </main>
  );
}
